import React, { useState, useMemo } from 'react';
import { Check, AlertCircle, TrendingUp, Zap } from 'lucide-react';

const ProfitCalculator: React.FC = () => {
  const [turnover, setTurnover] = useState<number>(60000);
  const [channelsToAdd, setChannelsToAdd] = useState({
    email: false,
    sms: false,
    whatsapp: false
  });

  const calculation = useMemo(() => {
    let multiplier = 0;
    let selectedCount = 0;

    if (channelsToAdd.email) { multiplier += 0.12; selectedCount++; }
    if (channelsToAdd.sms) { multiplier += 0.12; selectedCount++; }
    if (channelsToAdd.whatsapp) { multiplier += 0.12; selectedCount++; }

    // Average consistency addition is 20%
    const baseGrowth = 0.20; 
    const totalMultiplier = selectedCount > 0 ? (multiplier + baseGrowth) / 1.5 : 0; // Blending logic

    const addedRevenue = turnover * multiplier;
    const sixtyDayAdded = turnover * 0.20; // 20% avg in 60 days

    return {
      addedRevenue: Math.max(addedRevenue, selectedCount > 0 ? sixtyDayAdded : 0),
      selectedCount,
      percentage: (multiplier * 100).toFixed(0)
    };
  }, [turnover, channelsToAdd]);

  return (
    <section id="calculator" className="py-24 bg-neutral-950 relative overflow-hidden">
      <div className="max-w-7xl mx-auto px-4 relative z-10">
        <div className="text-center mb-16">
