              <div className="grid grid-cols-1 gap-4">
                {[
                  { id: 'email', label: 'שיווק במייל (A-Z)', icon: '📧' },
                  { id: 'sms', label: 'שיווק ב-SMS', icon: '📱' },
                  { id: 'whatsapp', label: 'שיווק ב-WhatsApp', icon: '💬' }
                ].map((item) => (
                  <button 
                    key={item.id}
                    onClick={() => setChannelsToAdd(p => ({...p, [item.id]: !p[item.id as keyof typeof p]}))}
                    className={`flex items-center justify-between p-8 rounded-[2rem] border-2 transition-all duration-500 ${channelsToAdd[item.id as keyof typeof channelsToAdd] ? 'bg-blue-600/20 border-blue-500 shadow-[0_0_30px_rgba(37,99,235,0.2)]' : 'bg-white/5 border-white/10 hover:bg-white/10'}`}
                  >
                    <span className="flex items-center gap-6 text-2xl font-black">
                      <span className="text-3xl">{item.icon}</span>
                      {item.label}
                    </span>
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all ${channelsToAdd[item.id as keyof typeof channelsToAdd] ? 'bg-blue-600 border-blue-500' : 'bg-white/10 border-white/20'}`}>
