            <div className="relative h-full bg-gradient-to-br from-neutral-900 to-black border border-white/10 p-12 md:p-20 rounded-[3rem] shadow-2xl flex flex-col justify-center">

              <div className="text-center space-y-12">
                <div>
                  <p className="text-blue-400 text-lg font-black uppercase tracking-[0.3em] mb-6">תוספת מחזור מוערכת (60 יום)</p>
                  <div className="flex flex-col items-center">
                    <span className="text-7xl md:text-[9rem] font-black tracking-tighter text-white leading-none">
                      ₪{calculation.addedRevenue.toLocaleString()}
