                    <TrendingUp className="h-10 w-10 text-green-400 mb-4" />
                    <p className="text-gray-500 text-sm font-black uppercase mb-2 tracking-widest">ROAS ממוצע</p>
                    <p className="text-5xl font-black text-white italic">14.0</p>
                    <p className="text-xs text-gray-600 mt-2">אחרי תוכנה ושירות</p>
                  </div>
                  <div className="bg-white/5 p-10 rounded-[2rem] border border-white/10 flex flex-col items-center">
                    <Zap className="h-10 w-10 text-yellow-400 mb-4" />
                    <p className="text-gray-500 text-sm font-black uppercase mb-2 tracking-widest">זמן לתוצאות</p>
                    <p className="text-5xl font-black text-white italic">60</p>
                    <p className="text-xs text-gray-600 mt-2">ימי עבודה ראשונים</p>
                  </div>
                </div>
              </div>

              <div className="mt-16 pt-12 border-t border-white/10 text-center">
                <p className="text-2xl text-gray-300 leading-relaxed font-medium mb-12">
                   לוקחים אחוז קטן מההכנסה שהבאנו לכם בלבד. <br /> <span className="text-white font-black underline decoration-blue-500">רק מהתוצאות.</span>
                </p>
                <a href="#contact" className={`inline-block w-full py-8 rounded-3xl font-black text-3xl transition-all shadow-2xl ${calculation.selectedCount > 0 ? 'bg-blue-600 text-white hover:bg-blue-500 hover:scale-105' : 'bg-neutral-800 text-neutral-500 cursor-not-allowed'}`}>
