                    <p className="text-3xl font-black text-white">₪{calculation.yearlyAdded.toLocaleString()}</p>
                  </div>
                  <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                    <p className="text-gray-500 text-xs font-bold uppercase mb-2">ROAS צפוי</p>
                    <p className="text-3xl font-black text-green-400">{displayRoas}</p>
