              </div>

              <div className="mt-12 pt-8 border-t border-white/10">
                <p className="text-gray-400 mb-8 leading-relaxed font-medium">
                  אנחנו מוסיפים בממוצע <span className="text-white font-bold">27% מהמחזור הקיים</span> ללקוחות שלנו (לפחות 20%), ומבקשים <span className="text-blue-400 font-bold">אחוזים בודדים רק מהתוצאות שהבאנו</span>.
                </p>
                <a href="#contact" className={`w-full py-6 rounded-2xl font-black text-xl text-center block transition-all shadow-xl ${calculation.selectedCount > 0 ? 'bg-blue-600 text-white hover:bg-blue-500 hover:scale-[1.02]' : 'bg-neutral-800 text-neutral-500 cursor-not-allowed'}`}>
                  אני רוצה להוסיף את הכסף הזה למחזור
                </a>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

