import React, { useState, useMemo, useEffect } from 'react';
import { Check, AlertCircle, BarChart } from 'lucide-react';

const ProfitCalculator: React.FC = () => {
  const [turnover, setTurnover] = useState<number>(60000);
  const [channelsToAdd, setChannelsToAdd] = useState({
    email: false,
    sms: false,
    whatsapp: false
  });
  const [displayRoas, setDisplayRoas] = useState<string>("14.0");

  const calculation = useMemo(() => {
    let multiplier = 0;
    let selectedCount = 0;

    if (channelsToAdd.email) { multiplier += 0.12; selectedCount++; }
    if (channelsToAdd.sms) { multiplier += 0.12; selectedCount++; }
    if (channelsToAdd.whatsapp) { multiplier += 0.12; selectedCount++; }

    // Base uplift starts at 20% for first 60 days if any selected, capping at 36%
    if (selectedCount === 0) multiplier = 0;
    else if (selectedCount === 1) multiplier = 0.20;
    else if (selectedCount === 2) multiplier = 0.27;
    else if (selectedCount === 3) multiplier = 0.36;

    const addedRevenue = turnover * multiplier;
    const yearlyAdded = addedRevenue * 12;

    return {
      addedRevenue,
      yearlyAdded,
      selectedCount,
      multiplierPercent: Math.round(multiplier * 100)
    };
  }, [turnover, channelsToAdd]);

  useEffect(() => {
    if (calculation.selectedCount === 0) {
      setDisplayRoas("0.0");
      return;
    }
    // ROAS around 14 as requested
    setDisplayRoas("14.0");
  }, [calculation.selectedCount]);

  return (
    <section id="calculator" className="py-32 bg-neutral-900/50 relative overflow-hidden text-right" dir="rtl">
      <div className="max-w-6xl mx-auto px-4 relative z-10">
        <div className="text-center mb-16">
          <div className="inline-flex items-center gap-2 px-4 py-1 rounded-full bg-blue-500/10 border border-blue-500/20 text-blue-400 text-sm font-bold mb-4 uppercase tracking-tighter">
            <BarChart className="w-4 h-4" />
            Profit Potential Calculator
          </div>
          <h2 className="text-4xl md:text-6xl font-black mb-6 tracking-tight font-assistant">כמה כסף נשאר לך על השולחן?</h2>
          <p className="text-xl text-gray-400 max-w-2xl mx-auto font-assistant">
            אנחנו מוסיפים בממוצע <span className="text-white font-bold">20% מהמחזור הקיים</span> לכל לקוח ב-60 הימים הראשונים.
            סמן את הכלים שתרצה להוסיף וגלה את הפוטנציאל.
          </p>
        </div>

        <div className="grid lg:grid-cols-2 gap-12 items-stretch">
          <div className="bg-black/40 border border-white/10 p-8 md:p-12 rounded-[2.5rem] backdrop-blur-xl flex flex-col justify-between">
            <div className="mb-12">
              <label className="block text-2xl font-black mb-8 font-assistant">מחזור חודשי נוכחי: ₪{turnover.toLocaleString()}</label>
              <input 
                type="range" 
                min="60000" 
                max="1000000" 
                step="10000"
                value={turnover}
                onChange={(e) => setTurnover(Number(e.target.value))}
                className="w-full h-4 bg-neutral-800 rounded-full appearance-none cursor-pointer accent-blue-500"
              />
              <div className="flex justify-between mt-6 text-gray-500 text-sm font-black font-assistant uppercase tracking-widest">
                <span>₪60,000</span>
                <span>₪1,000,000+</span>
              </div>
            </div>

            <div className="space-y-6 font-assistant">
              <p className="text-lg font-bold mb-6 flex items-center gap-2 text-blue-400">
                <AlertCircle className="w-5 h-5" />
                אילו ערוצי שיווק חסרים לך כרגע?
              </p>

              <div className="grid grid-cols-1 gap-4">
                {[
                  { id: 'email', label: 'שיווק במייל (Email Marketing)', icon: '📧' },
                  { id: 'sms', label: 'שיווק ב-SMS', icon: '📱' },
                  { id: 'whatsapp', label: 'שיווק ב-WhatsApp', icon: '💬' }
                ].map((item) => (
                  <button 
                    key={item.id}
                    onClick={() => setChannelsToAdd(p => ({...p, [item.id]: !p[item.id as keyof typeof p]}))}
                    className={`flex items-center justify-between p-6 rounded-2xl border transition-all duration-300 transform ${channelsToAdd[item.id as keyof typeof channelsToAdd] ? 'bg-blue-600/20 border-blue-500 scale-[1.02] shadow-[0_0_20px_rgba(37,99,235,0.2)]' : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-white/30'}`}
                  >
                    <span className="flex items-center gap-5 text-xl font-bold">
                      <span className="text-3xl">{item.icon}</span>
                      {item.label}
                    </span>
                    <span className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${channelsToAdd[item.id as keyof typeof channelsToAdd] ? 'bg-blue-500' : 'bg-white/10'}`}>
                      {channelsToAdd[item.id as keyof typeof channelsToAdd] && <Check className="w-6 h-6 text-white" />}
                    </span>
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="relative group">
            <div className="absolute inset-0 bg-blue-600 rounded-[2.5rem] blur-3xl opacity-20 group-hover:opacity-40 transition-opacity"></div>
            <div className="relative h-full bg-gradient-to-br from-neutral-900 via-neutral-900 to-black border border-white/10 p-10 md:p-14 rounded-[2.5rem] shadow-2xl flex flex-col font-assistant">

              <div className="flex-grow space-y-16">
                <div className="text-center md:text-right">
                  <p className="text-blue-400 text-sm font-black uppercase tracking-[0.3em] mb-6">פוטנציאל תוספת מחזור ({calculation.multiplierPercent}%)</p>
                  <div className="flex items-baseline justify-center md:justify-start gap-3">
                    <span className="text-7xl md:text-[7rem] font-black tracking-tighter text-white drop-shadow-2xl">
                      ₪{calculation.addedRevenue.toLocaleString()}
                    </span>
                  </div>
                  {calculation.selectedCount === 0 && (
                    <p className="text-gray-500 mt-6 text-xl animate-pulse italic">בחרו לפחות ערוץ אחד כדי לראות את הקסם...</p>
                  )}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                  <div className="bg-white/5 p-8 rounded-[2rem] border border-white/5 backdrop-blur-sm">
                    <p className="text-gray-500 text-xs font-black uppercase mb-3 tracking-widest">תוספת שנתית מוערכת</p>
                    <p className="text-4xl font-black text-white">₪{calculation.yearlyAdded.toLocaleString()}</p>
                  </div>
                  <div className="bg-white/5 p-8 rounded-[2rem] border border-white/5 backdrop-blur-sm">
                    <p className="text-gray-500 text-xs font-black uppercase mb-3 tracking-widest">ROAS ממוצע צפוי</p>
                    <p className="text-4xl font-black text-blue-400">{displayRoas}</p>
                  </div>
                </div>
              </div>

              <div className="mt-16 pt-10 border-t border-white/10">
                <p className="text-gray-400 mb-10 text-xl leading-relaxed">
                  הכנסנו כבר קרוב ל-<span className="text-white font-black">10 מיליון ש"ח</span> ללקוחות שלנו בארץ. <br />
                  אנחנו לוקחים רק <span className="text-blue-400 font-bold">אחוז קטן מההצלחה</span> שהבאנו לכם.
                </p>
                <button 
                  onClick={() => document.getElementById('contact-quick')?.scrollIntoView({ behavior: 'smooth' })}
                  className={`w-full py-7 rounded-2xl font-black text-2xl text-center block transition-all shadow-2xl ${calculation.selectedCount > 0 ? 'bg-white text-black hover:bg-blue-600 hover:text-white hover:scale-[1.03]' : 'bg-neutral-800 text-neutral-500 cursor-not-allowed'}`}
                >
                  בואו נכניס את הכסף הזה לחנות
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

